{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/db.js", "content": "/**
 * IndexedDB wrapper for HarborGate data.
 */
const DB_NAME = 'harborgate';
const DB_VERSION = 1;

const STORES = {
  visitors: { keyPath: 'id', autoIncrement: true },
  reservations: { keyPath: 'id', autoIncrement: true },
  content: { keyPath: 'id', autoIncrement: true },
  notifications: { keyPath: 'id', autoIncrement: true },
  zones: { keyPath: 'id', autoIncrement: true }
};

let dbInstance = null;

function open() {
  if (dbInstance) return Promise.resolve(dbInstance);

  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onupgradeneeded = (event) => {
      const db = event.target.result;
      for (const [name, opts] of Object.entries(STORES)) {
        if (!db.objectStoreNames.contains(name)) {
          db.createObjectStore(name, opts);
        }
      }
    };

    request.onsuccess = (event) => {
      dbInstance = event.target.result;
      resolve(dbInstance);
    };

    request.onerror = (event) => {
      reject(event.target.error);
    };
  });
}

async function getStore(storeName, mode = 'readonly') {
  const db = await open();
  const tx = db.transaction(storeName, mode);
  return tx.objectStore(storeName);
}

function promisify(request) {
  return new Promise((resolve, reject) => {
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

const DB = {
  async getAll(storeName) {
    const store = await getStore(storeName);
    return promisify(store.getAll());
  },

  async get(storeName, id) {
    const store = await getStore(storeName);
    return promisify(store.get(id));
  },

  async add(storeName, record) {
    const store = await getStore(storeName, 'readwrite');
    return promisify(store.add(record));
  },

  async put(storeName, record) {
    const store = await getStore(storeName, 'readwrite');
    return promisify(store.put(record));
  },

  async remove(storeName, id) {
    const store = await getStore(storeName, 'readwrite');
    return promisify(store.delete(id));
  },

  async clear(storeName) {
    const store = await getStore(storeName, 'readwrite');
    return promisify(store.clear());
  },

  async close() {
    if (dbInstance) {
      dbInstance.close();
      dbInstance = null;
    }
  }
};

export default DB;
"}

