{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/views/dashboard.js", "content": "import DB from '../db.js';
import { createNotificationBadge } from '../components/notifications.js';

export async function renderDashboard(container) {
  const [visitors, reservations, notifications, content] = await Promise.all([
    DB.getAll('visitors'),
    DB.getAll('reservations'),
    DB.getAll('notifications'),
    DB.getAll('content')
  ]);

  const activeVisitors = visitors.filter(v => v.status === 'checked-in').length;
  const pendingReservations = reservations.filter(r => r.status === 'pending').length;
  const unreadNotifications = notifications.filter(n => !n.read).length;
  const flaggedContent = content.filter(c => c.flagged).length;

  container.innerHTML = `
    <div class="dashboard">
      <h1>HarborGate Dashboard</h1>
      <div class="stats-grid">
        <div class="stat-card" data-link="/visitors">
          <h3>Active Visitors</h3>
          <span class="stat-number">${activeVisitors}</span>
        </div>
        <div class="stat-card" data-link="/reservations">
          <h3>Pending Reservations</h3>
          <span class="stat-number">${pendingReservations}</span>
        </div>
        <div class="stat-card" data-link="/notifications">
          <h3>Unread Notifications</h3>
          <span class="stat-number">${unreadNotifications}</span>
          ${createNotificationBadge(unreadNotifications)}
        </div>
        <div class="stat-card" data-link="/content">
          <h3>Flagged Content</h3>
          <span class="stat-number">${flaggedContent}</span>
        </div>
      </div>
      <div class="quick-actions">
        <button class="btn btn-primary" data-action="new-visitor">Register Visitor</button>
        <button class="btn btn-secondary" data-action="new-reservation">New Reservation</button>
        <button class="btn btn-secondary" data-action="scan-content">Scan Content</button>
      </div>
    </div>
  `;

  container.querySelectorAll('[data-link]').forEach(card => {
    card.addEventListener('click', () => {
      window.location.hash = card.dataset.link;
    });
  });

  container.querySelector('[data-action="new-visitor"]')?.addEventListener('click', () => {
    window.location.hash = '/visitors?action=new';
  });
  container.querySelector('[data-action="new-reservation"]')?.addEventListener('click', () => {
    window.location.hash = '/reservations?action=new';
  });
  container.querySelector('[data-action="scan-content"]')?.addEventListener('click', () => {
    window.location.hash = '/content?action=scan';
  });
}
"}

