{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/views/visitors.js", "content": "import DB from '../db.js';
import { showModal, closeModal } from '../components/modal.js';
import { renderTable } from '../components/table.js';
import { showNotification } from '../components/notifications.js';

export async function renderVisitors(container) {
  const visitors = await DB.getAll('visitors');

  container.innerHTML = `
    <div class="view-header">
      <h1>Visitor Management</h1>
      <button class="btn btn-primary" id="add-visitor-btn">+ Add Visitor</button>
    </div>
    <div class="filters">
      <input type="text" id="visitor-search" placeholder="Search visitors..." class="input" />
      <select id="visitor-status-filter" class="input">
        <option value="">All Statuses</option>
        <option value="checked-in">Checked In</option>
        <option value="checked-out">Checked Out</option>
        <option value="pending">Pending</option>
        <option value="denied">Denied</option>
      </select>
    </div>
    <div id="visitors-table"></div>
  `;

  const columns = [
    { key: 'name', label: 'Name' },
    { key: 'email', label: 'Email' },
    { key: 'purpose', label: 'Purpose' },
    { key: 'status', label: 'Status', render: (val) => `<span class="badge badge-${val}">${val}</span>` },
    { key: 'checkIn', label: 'Check-In Time' },
    { key: 'actions', label: 'Actions', render: (_, row) => `
      <button class="btn btn-sm" data-action="edit" data-id="${row.id}">Edit</button>
      <button class="btn btn-sm btn-danger" data-action="delete" data-id="${row.id}">Delete</button>
      ${row.status === 'pending' ? `<button class="btn btn-sm btn-primary" data-action="checkin" data-id="${row.id}">Check In</button>` : ''}
      ${row.status === 'checked-in' ? `<button class="btn btn-sm btn-secondary" data-action="checkout" data-id="${row.id}">Check Out</button>` : ''}
    `}
  ];

  function display(data) {
    renderTable(document.getElementById('visitors-table'), columns, data);
    bindTableActions();
  }

  display(visitors);

  document.getElementById('visitor-search').addEventListener('input', (e) => {
    const q = e.target.value.toLowerCase();
    display(visitors.filter(v => v.name.toLowerCase().includes(q) || v.email.toLowerCase().includes(q)));
  });

  document.getElementById('visitor-status-filter').addEventListener('change', (e) => {
    const status = e.target.value;
    display(status ? visitors.filter(v => v.status === status) : visitors);
  });

  document.getElementById('add-visitor-btn').addEventListener('click', () => openVisitorForm());

  function bindTableActions() {
    document.querySelectorAll('[data-action="edit"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const visitor = await DB.get('visitors', Number(btn.dataset.id));
        if (visitor) openVisitorForm(visitor);
      });
    });

    document.querySelectorAll('[data-action="delete"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        await DB.remove('visitors', Number(btn.dataset.id));
        showNotification('Visitor deleted', 'success');
        renderVisitors(container);
      });
    });

    document.querySelectorAll('[data-action="checkin"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const visitor = await DB.get('visitors', Number(btn.dataset.id));
        if (visitor) {
          visitor.status = 'checked-in';
          visitor.checkIn = new Date().toLocaleString();
          await DB.put('visitors', visitor);
          await DB.add('notifications', {
            message: `${visitor.name} checked in`,
            type: 'info',
            read: false,
            timestamp: Date.now()
          });
          showNotification('Visitor checked in', 'success');
          renderVisitors(container);
        }
      });
    });

    document.querySelectorAll('[data-action="checkout"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const visitor = await DB.get('visitors', Number(btn.dataset.id));
        if (visitor) {
          visitor.status = 'checked-out';
          visitor.checkOut = new Date().toLocaleString();
          await DB.put('visitors', visitor);
          showNotification('Visitor checked out', 'success');
          renderVisitors(container);
        }
      });
    });
  }

  function openVisitorForm(existing = null) {
    const title = existing ? 'Edit Visitor' : 'Register Visitor';
    showModal(title, `
      <form id="visitor-form">
        <label class="form-label">Name
          <input type="text" name="name" class="input" value="${existing?.name || ''}" required />
        </label>
        <label class="form-label">Email
          <input type="email" name="email" class="input" value="${existing?.email || ''}" required />
        </label>
        <label class="form-label">Phone
          <input type="tel" name="phone" class="input" value="${existing?.phone || ''}" />
        </label>
        <label class="form-label">Purpose
          <select name="purpose" class="input" required>
