const ZONE_LAYOUT = [
  { id: 'lobby', label: 'Lobby', x: 10, y: 10, w: 180, h: 100, color: '#4a9eff' },
  { id: 'office-a', label: 'Office A', x: 210, y: 10, w: 160, h: 100, color: '#34d399' },
  { id: 'office-b', label: 'Office B', x: 390, y: 10, w: 160, h: 100, color: '#34d399' },
  { id: 'warehouse', label: 'Warehouse', x: 10, y: 130, w: 340, h: 120, color: '#fbbf24' },
  { id: 'dock', label: 'Dock', x: 370, y: 130, w: 180, h: 120, color: '#f87171' }
];

export async function renderMap(container) {
  const visitors = await DB.getAll('visitors');
  const activeByZone = {};

  for (const v of visitors) {
    if (v.status === 'checked-in' && v.zone) {
      activeByZone[v.zone] = (activeByZone[v.zone] || 0) + 1;
    }
  }

  container.innerHTML = `
    <div class="view-header">
      <h1>Facility Map</h1>
    </div>
    <div class="map-container">
      <svg id="facility-map" viewBox="0 0 570 270" class="facility-map">
        ${ZONE_LAYOUT.map(z => `
          <g class="zone-group" data-zone="${z.id}">
            <rect x="${z.x}" y="${z.y}" width="${z.w}" height="${z.h}"
                  rx="8" fill="${z.color}22" stroke="${z.color}" stroke-width="2" />
            <text x="${z.x + z.w / 2}" y="${z.y + 30}" text-anchor="middle"
                  class="zone-label">${z.label}</text>
            <text x="${z.x + z.w / 2}" y="${z.y + 55}" text-anchor="middle"
                  class="zone-count">${activeByZone[z.id] || 0} visitors</text>
          </g>
        `).join('')}
      </svg>
    </div>
    <div id="zone-detail" class="zone-detail"></div>
  `;

  container.querySelectorAll('.zone-group').forEach(g => {
    g.addEventListener('click', async () => {
      const zoneId = g.dataset.zone;
      const zoneVisitors = visitors.filter(v => v.status === 'checked-in' && v.zone === zoneId);
      const detail = document.getElementById('zone-detail');
      detail.innerHTML = `
        <h3>${ZONE_LAYOUT.find(z => z.id === zoneId).label}</h3>
        ${zoneVisitors.length === 0 ? '<p>No active visitors</p>' : `
          <ul>${zoneVisitors.map(v => `<li>${v.name} — ${v.purpose || 'N/A'}</li>`).join('')}</ul>
        `}
      `;
    });
  });
}
"}

