        ${ZONE_LAYOUT.map(z => `
          <g class="zone-group" data-zone="${z.id}">
            <rect x="${z.x}" y="${z.y}" width="${z.w}" height="${z.h}"
                  rx="8" fill="${z.color}22" stroke="${z.color}" stroke-width="2" />
            <text x="${z.x + z.w / 2}" y="${z.y + 30}" text-anchor="middle"
                  class="zone-label">${z.label}</text>
            <text x="${z.x + z.w / 2}" y="${z.y + 55}" text-anchor="middle"
                  class="zone-count">${activeByZone[z.id] || 0} visitors</text>
          </g>
        `).join('')}
      </svg>
    </div>
    <div id="zone-detail" class="zone-detail"></div>
  `;

  container.querySelectorAll('.zone-group').forEach(g => {
    g.addEventListener('click', async () => {
      const zoneId = g.dataset.zone;
      const zoneVisitors = visitors.filter(v => v.status === 'checked-in' && v.zone === zoneId);
      const detail = document.getElementById('zone-detail');
      detail.innerHTML = `
        <h3>${ZONE_LAYOUT.find(z => z.id === zoneId).label}</h3>
        ${zoneVisitors.length === 0 ? '<p>No active visitors</p>' : `
          <ul>${zoneVisitors.map(v => `<li>${v.name} — ${v.purpose || 'N/A'}</li>`).join('')}</ul>
        `}
      `;
    });
  });
}
"}

