import { showModal, closeModal } from '../components/modal.js';
import { renderTable } from '../components/table.js';
import { showNotification } from '../components/notifications.js';

const COMPLIANCE_RULES = [
  { id: 'pii', label: 'PII Detection', pattern: /\b\d{3}-\d{2}-\d{4}\b|\b\d{16}\b/g, description: 'SSN or credit card numbers' },
  { id: 'profanity', label: 'Profanity Filter', pattern: /\b(banned|blocked|restricted)\b/gi, description: 'Restricted words' },
  { id: 'url', label: 'External URL', pattern: /https?:\/\/[^\s]+/g, description: 'External URLs' }
];

function scanContent(text) {
  const violations = [];
  for (const rule of COMPLIANCE_RULES) {
    const matches = text.match(rule.pattern);
    if (matches) {
      violations.push({ ruleId: rule.id, label: rule.label, matches: matches.length, description: rule.description });
    }
  }
  return violations;
}

export async function renderContent(container) {
  const items = await DB.getAll('content');

  container.innerHTML = `
    <div class="view-header">
      <h1>Content Compliance</h1>
      <button class="btn btn-primary" id="scan-content-btn">+ Scan New Content</button>
    </div>
    <div class="filters">
      <input type="text" id="content-search" placeholder="Search content..." class="input" />
      <select id="content-flag-filter" class="input">
        <option value="">All</option>
        <option value="flagged">Flagged</option>
        <option value="clean">Clean</option>
      </select>
    </div>
    <div id="content-table"></div>
  `;

  const columns = [
    { key: 'title', label: 'Title' },
    { key: 'source', label: 'Source' },
    { key: 'flagged', label: 'Status', render: (val) => val
      ? '<span class="badge badge-denied">Flagged</span>'
      : '<span class="badge badge-approved">Clean</span>' },
    { key: 'violationCount', label: 'Violations' },
    { key: 'scannedAt', label: 'Scanned', render: (val) => new Date(val).toLocaleString() },
    { key: 'actions', label: 'Actions', render: (_, row) => `
      <button class="btn btn-sm" data-action="view" data-id="${row.id}">View</button>
      <button class="btn btn-sm btn-danger" data-action="delete" data-id="${row.id}">Delete</button>
    `}
  ];

  function display(data) {
    renderTable(document.getElementById('content-table'), columns, data);
    bindActions();
  }

  display(items);

  document.getElementById('content-search').addEventListener('input', (e) => {
    const q = e.target.value.toLowerCase();
    display(items.filter(i => i.title.toLowerCase().includes(q)));
  });

  document.getElementById('content-flag-filter').addEventListener('change', (e) => {
    const v = e.target.value;
    if (v === 'flagged') display(items.filter(i => i.flagged));
    else if (v === 'clean') display(items.filter(i => !i.flagged));
    else display(items);
  });

  document.getElementById('scan-content-btn').addEventListener('click', openScanForm);

  function bindActions() {
    document.querySelectorAll('[data-action="view"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const item = await DB.get('content', Number(btn.dataset.id));
        if (item) {
          showModal('Content Details', `
            <h3>${item.title}</h3>
            <p><strong>Source:</strong> ${item.source}</p>
            <p><strong>Status:</strong> ${item.flagged ? 'Flagged' : 'Clean'}</p>
            <div class="content-body">${item.body}</div>
            ${item.violations?.length ? `
              <h4>Violations</h4>
              <ul>${item.violations.map(v => `<li>${v.label}: ${v.matches} match(es) — ${v.description}</li>`).join('')}</ul>
            ` : ''}
            <div class="form-actions">
              <button class="btn btn-secondary" id="close-detail">Close</button>
            </div>
          `);
          document.getElementById('close-detail').addEventListener('click', closeModal);
        }
      });
    });

    document.querySelectorAll('[data-action="delete"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        await DB.remove('content', Number(btn.dataset.id));
        showNotification('Content removed', 'success');
        renderContent(container);
      });
    });
  }

  function openScanForm() {
    showModal('Scan Content', `
      <form id="content-form">
        <label class="form-label">Title
          <input type="text" name="title" class="input" required />
        </label>
        <label class="form-label">Source
          <input type="text" name="source" class="input" placeholder="e.g., email, document, upload" required />
        </label>
        <label class="form-label">Content Body
          <textarea name="body" class="input" rows="6" required></textarea>
        </label>
        <div class="form-actions">
          <button type="submit" class="btn btn-primary">Scan & Save</button>
          <button type="button" class="btn btn-secondary" id="cancel-content">Cancel</button>
        </div>
      </form>
    `);

    document.getElementById('cancel-content').addEventListener('click', closeModal);
    document.getElementById('content-form').addEventListener('submit', async (e) => {
      e.preventDefault();
      const fd = new FormData(e.target);
      const data = Object.fromEntries(fd);

      const violations = scanContent(data.body);
      data.violations = violations;
      data.violationCount = violations.length;
      data.flagged = violations.length > 0;
      data.scannedAt = Date.now();

      await DB.add('content', data);

      if (data.flagged) {
        await DB.add('notifications', {
          message: `Content "${data.title}" flagged with ${violations.length} violation(s)`,
          type: 'warning',
          read: false,
          timestamp: Date.now()
        });
      }

      showNotification(data.flagged ? 'Content flagged!' : 'Content is clean', data.flagged ? 'warning' : 'success');
      closeModal();
      renderContent(container);
    });
  }
}
"}

