{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/views/settings.js", "content": "import Crypto from '../crypto.js';
import { showNotification } from '../components/notifications.js';

export async function renderSettings(container) {
  const currentTheme = localStorage.getItem('hg_theme') || 'light';
  const sessionToken = localStorage.getItem('hg_session_token') || '';

  container.innerHTML = `
    <div class="view-header">
      <h1>Settings</h1>
    </div>
    <div class="settings-grid">
      <section class="settings-section">
        <h2>Appearance</h2>
        <label class="form-label">Theme
          <select id="theme-select" class="input">
            <option value="light" ${currentTheme === 'light' ? 'selected' : ''}>Light</option>
            <option value="dark" ${currentTheme === 'dark' ? 'selected' : ''}>Dark</option>
          </select>
        </label>
      </section>

      <section class="settings-section">
        <h2>Security</h2>
        <form id="encryption-form">
          <label class="form-label">Encryption Password
            <input type="password" id="enc-password" class="input" placeholder="Set password for data encryption" />
          </label>
          <label class="form-label">Test Message
            <input type="text" id="enc-test" class="input" placeholder="Type a message to encrypt/decrypt" />
          </label>
          <div class="form-actions">
            <button type="button" class="btn btn-primary" id="encrypt-btn">Encrypt</button>
            <button type="button" class="btn btn-secondary" id="decrypt-btn">Decrypt</button>
          </div>
          <div id="crypto-result" class="crypto-result"></div>
        </form>
      </section>

      <section class="settings-section">
        <h2>Session</h2>
        <p>Token: <code>${sessionToken ? sessionToken.slice(0, 16) + '...' : 'None'}</code></p>
        <button class="btn btn-primary" id="generate-token">Generate Token</button>
        <button class="btn btn-danger" id="clear-session">Clear Session</button>
      </section>

      <section class="settings-section">
        <h2>Data Management</h2>
        <button class="btn btn-danger" id="clear-all-data">Clear All Data</button>
        <p class="hint">This will remove all visitors, reservations, content, and notifications from IndexedDB.</p>
      </section>
    </div>
  `;

  document.getElementById('theme-select').addEventListener('change', (e) => {
    localStorage.setItem('hg_theme', e.target.value);
    document.documentElement.setAttribute('data-theme', e.target.value);
    showNotification('Theme updated', 'success');
  });

  document.getElementById('encrypt-btn').addEventListener('click', async () => {
    const pw = document.getElementById('enc-password').value;
    const msg = document.getElementById('enc-test').value;
    if (!pw || !msg) return showNotification('Enter password and message', 'warning');
    const encrypted = await Crypto.encrypt(msg, pw);
    document.getElementById('crypto-result').textContent = encrypted;
  });

  document.getElementById('decrypt-btn').addEventListener('click', async () => {
    const pw = document.getElementById('enc-password').value;
    const cipher = document.getElementById('crypto-result').textContent;
    if (!pw || !cipher) return showNotification('Encrypt something first', 'warning');
    try {
      const decrypted = await Crypto.decrypt(cipher, pw);
      document.getElementById('enc-test').value = decrypted;
      showNotification('Decrypted successfully', 'success');
    } catch {
      showNotification('Decryption failed — wrong password?', 'error');
    }
  });

  document.getElementById('generate-token').addEventListener('click', () => {
    const token = Crypto.generateId();
    localStorage.setItem('hg_session_token', token);
    showNotification('Session token generated', 'success');
    renderSettings(container);
  });

  document.getElementById('clear-session').addEventListener('click', () => {
    localStorage.removeItem('hg_session_token');
    showNotification('Session cleared', 'success');
    renderSettings(container);
  });

  document.getElementById('clear-all-data').addEventListener('click', async () => {
    const { default: DB } = await import('../db.js');
    for (const store of ['visitors', 'reservations', 'content', 'notifications', 'zones']) {
      await DB.clear(store);
    }
    showNotification('All data cleared', 'success');
  });
}
"}

