 * Device service layer — HTTP/MQTT/WebSocket adapters.
 * Provides a unified interface for device communication.
 * In this client-only app, these simulate device interactions.
 */
const DeviceService = {
  _devices: [],
  _listeners: [],

  registerDevice(device) {
    this._devices.push({ ...device, status: 'online', lastSeen: Date.now() });
    this._emit('device:registered', device);
  },

  getDevices() {
    return [...this._devices];
  },

  sendCommand(deviceId, command) {
    const device = this._devices.find(d => d.id === deviceId);
    if (!device) throw new Error(`Device ${deviceId} not found`);
    device.lastCommand = command;
    device.lastSeen = Date.now();
    this._emit('device:command', { deviceId, command });
    return { success: true, deviceId, command };
  },

  onEvent(callback) {
    this._listeners.push(callback);
    return () => {
      this._listeners = this._listeners.filter(l => l !== callback);
    };
  },

  _emit(type, payload) {
    for (const listener of this._listeners) {
      listener({ type, payload, timestamp: Date.now() });
    }
  },

  simulateHeartbeat() {
    for (const device of this._devices) {
      device.lastSeen = Date.now();
    }
    this._emit('devices:heartbeat', { count: this._devices.length });
  }
};

export default DeviceService;
"}

