{"file_path": "/home/eren/Documents/task4/Harborgate/repo/unit_tests/store.test.js", "content": "import { describe, it, beforeEach } from 'node:test';
import assert from 'node:assert/strict';

// Inline store implementation for Node testing (no DOM dependency)
function createStore() {
  let state = {};
  let listeners = [];

  return {
    get(key) { return state[key]; },
    set(key, value) {
      state[key] = value;
      for (const l of listeners) l(key, value);
    },
    getAll() { return { ...state }; },
    subscribe(listener) {
      listeners.push(listener);
      return () => { listeners = listeners.filter(l => l !== listener); };
    },
    reset() { state = {}; listeners = []; }
  };
}

describe('Store', () => {
  let store;

  beforeEach(() => {
    store = createStore();
  });

  it('should set and get values', () => {
    store.set('name', 'HarborGate');
    assert.equal(store.get('name'), 'HarborGate');
  });

  it('should return undefined for unset keys', () => {
    assert.equal(store.get('missing'), undefined);
  });

  it('should return all state', () => {
    store.set('a', 1);
    store.set('b', 2);
    assert.deepEqual(store.getAll(), { a: 1, b: 2 });
  });

  it('should notify subscribers on set', () => {
    const events = [];
    store.subscribe((key, value) => events.push({ key, value }));
    store.set('x', 42);
    assert.equal(events.length, 1);
    assert.deepEqual(events[0], { key: 'x', value: 42 });
  });

  it('should allow unsubscribing', () => {
    const events = [];
    const unsub = store.subscribe((key, value) => events.push({ key, value }));
    store.set('a', 1);
    unsub();
    store.set('b', 2);
    assert.equal(events.length, 1);
  });

  it('should reset state and listeners', () => {
    store.set('key', 'val');
    const events = [];
    store.subscribe((k, v) => events.push(v));
    store.reset();
    assert.equal(store.get('key'), undefined);
    // After reset, setting should not trigger old listeners
    store.set('key2', 'val2');
    assert.equal(events.length, 0);
  });

  it('should overwrite existing values', () => {
    store.set('name', 'old');
    store.set('name', 'new');
    assert.equal(store.get('name'), 'new');
  });

  it('should support multiple subscribers', () => {
    let count1 = 0, count2 = 0;
    store.subscribe(() => count1++);
    store.subscribe(() => count2++);
    store.set('x', 1);
    assert.equal(count1, 1);
    assert.equal(count2, 1);
  });
});
"}

