import assert from 'node:assert/strict';
import { webcrypto } from 'node:crypto';

// Polyfill for Node.js
if (!globalThis.crypto) globalThis.crypto = webcrypto;

const SALT_LENGTH = 16;
const IV_LENGTH = 12;
const ITERATIONS = 100000;

async function deriveKey(password, salt) {
  const enc = new TextEncoder();
  const keyMaterial = await crypto.subtle.importKey(
    'raw', enc.encode(password), 'PBKDF2', false, ['deriveKey']
  );
  return crypto.subtle.deriveKey(
    { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
    keyMaterial,
    { name: 'AES-GCM', length: 256 },
    false,
    ['encrypt', 'decrypt']
  );
}

const Crypto = {
  async encrypt(plaintext, password) {
    const enc = new TextEncoder();
    const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
    const key = await deriveKey(password, salt);
    const ciphertext = await crypto.subtle.encrypt({ name: 'AES-GCM', iv }, key, enc.encode(plaintext));
    const combined = new Uint8Array(salt.length + iv.length + ciphertext.byteLength);
    combined.set(salt, 0);
    combined.set(iv, salt.length);
    combined.set(new Uint8Array(ciphertext), salt.length + iv.length);
    return Buffer.from(combined).toString('base64');
  },

  async decrypt(encoded, password) {
    const data = Buffer.from(encoded, 'base64');
    const salt = data.subarray(0, SALT_LENGTH);
    const iv = data.subarray(SALT_LENGTH, SALT_LENGTH + IV_LENGTH);
    const ciphertext = data.subarray(SALT_LENGTH + IV_LENGTH);
    const key = await deriveKey(password, salt);
    const plainBuffer = await crypto.subtle.decrypt({ name: 'AES-GCM', iv }, key, ciphertext);
    return new TextDecoder().decode(plainBuffer);
  },

  generateId() {
    return crypto.getRandomValues(new Uint8Array(16))
      .reduce((s, b) => s + b.toString(16).padStart(2, '0'), '');
  }
};

describe('Crypto', () => {
  it('should encrypt and decrypt a string', async () => {
    const message = 'Hello HarborGate';
    const password = 'test-password-123';
    const encrypted = await Crypto.encrypt(message, password);
    assert.notEqual(encrypted, message);
    const decrypted = await Crypto.decrypt(encrypted, password);
    assert.equal(decrypted, message);
  });

  it('should fail decryption with wrong password', async () => {
    const encrypted = await Crypto.encrypt('secret', 'right-password');
    await assert.rejects(
      () => Crypto.decrypt(encrypted, 'wrong-password'),
      (err) => err instanceof Error
    );
  });

  it('should produce different ciphertexts for same input', async () => {
    const msg = 'same message';
    const pw = 'password';
