import assert from 'node:assert/strict';

// Inline device service for Node testing
function createDeviceService() {
  let devices = [];
  let listeners = [];

  function emit(type, payload) {
    for (const l of listeners) l({ type, payload, timestamp: Date.now() });
  }

  return {
    registerDevice(device) {
      devices.push({ ...device, status: 'online', lastSeen: Date.now() });
      emit('device:registered', device);
    },
    getDevices() { return [...devices]; },
    sendCommand(deviceId, command) {
      const device = devices.find(d => d.id === deviceId);
      if (!device) throw new Error(`Device ${deviceId} not found`);
      device.lastCommand = command;
      device.lastSeen = Date.now();
      emit('device:command', { deviceId, command });
      return { success: true, deviceId, command };
    },
    onEvent(callback) {
      listeners.push(callback);
      return () => { listeners = listeners.filter(l => l !== callback); };
    },
    simulateHeartbeat() {
      for (const d of devices) d.lastSeen = Date.now();
      emit('devices:heartbeat', { count: devices.length });
    },
    reset() { devices = []; listeners = []; }
  };
}

describe('DeviceService', () => {
  let svc;

  beforeEach(() => {
    svc = createDeviceService();
  });

  it('should register a device', () => {
    svc.registerDevice({ id: 'gate-1', name: 'Main Gate' });
    assert.equal(svc.getDevices().length, 1);
    assert.equal(svc.getDevices()[0].id, 'gate-1');
  });

  it('should set device status to online', () => {
    svc.registerDevice({ id: 'cam-1', name: 'Camera' });
    assert.equal(svc.getDevices()[0].status, 'online');
  });

  it('should send command to device', () => {
    svc.registerDevice({ id: 'd1', name: 'Device 1' });
    const result = svc.sendCommand('d1', 'open');
    assert.equal(result.success, true);
    assert.equal(result.command, 'open');
  });

  it('should throw on command to unknown device', () => {
    assert.throws(() => svc.sendCommand('missing', 'open'), /not found/);
  });

  it('should emit events on register', () => {
    const events = [];
    svc.onEvent(e => events.push(e));
    svc.registerDevice({ id: 'd1', name: 'D1' });
    assert.equal(events.length, 1);
    assert.equal(events[0].type, 'device:registered');
  });

  it('should emit events on command', () => {
    const events = [];
    svc.registerDevice({ id: 'd1', name: 'D1' });
    svc.onEvent(e => events.push(e));
    svc.sendCommand('d1', 'lock');
    assert.equal(events.length, 1);
    assert.equal(events[0].type, 'device:command');
  });

  it('should allow unsubscribing from events', () => {
    const events = [];
    const unsub = svc.onEvent(e => events.push(e));
    svc.registerDevice({ id: 'd1', name: 'D1' });
    unsub();
    svc.registerDevice({ id: 'd2', name: 'D2' });
    assert.equal(events.length, 1);
  });

  it('should update lastSeen on heartbeat', () => {
    svc.registerDevice({ id: 'd1', name: 'D1' });
    const before = svc.getDevices()[0].lastSeen;
    svc.simulateHeartbeat();
    assert.ok(svc.getDevices()[0].lastSeen >= before);
  });

  it('should return copies of devices array', () => {
    svc.registerDevice({ id: 'd1', name: 'D1' });
    const a = svc.getDevices();
    const b = svc.getDevices();
    assert.notEqual(a, b);
  });
});
"}

