{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/services/auth.js", "content": "/**
 * Authentication & Session service.
 * - Password policy: min 12 chars, 1 upper, 1 lower, 1 number, 1 symbol
 * - 5 failed attempts → 15 min lockout
 * - 30-min idle timeout, "Extend Session" prompt at 25 min
 * - Session token in localStorage
 */
import DB from '../db.js';
import Crypto from '../crypto.js';
import Store from '../store.js';
import { addAuditLog } from './audit.js';

const SESSION_KEY = 'hg_session';
const SESSION_TIMEOUT = 30 * 60 * 1000;       // 30 minutes
const SESSION_WARNING = 25 * 60 * 1000;       // 25 minutes
const LOCKOUT_DURATION = 15 * 60 * 1000;      // 15 minutes
const MAX_ATTEMPTS = 5;

let idleTimer = null;
let warningTimer = null;

const PASSWORD_RULES = [
  { test: (p) => p.length >= 12, msg: 'Minimum 12 characters' },
  { test: (p) => /[A-Z]/.test(p), msg: 'At least 1 uppercase letter' },
  { test: (p) => /[a-z]/.test(p), msg: 'At least 1 lowercase letter' },
  { test: (p) => /[0-9]/.test(p), msg: 'At least 1 number' },
  { test: (p) => /[^A-Za-z0-9]/.test(p), msg: 'At least 1 symbol' }
];

export function validatePassword(password) {
  const failures = PASSWORD_RULES.filter(r => !r.test(password));
  return { valid: failures.length === 0, errors: failures.map(f => f.msg) };
}

export function isAccountLocked(user) {
  if (!user.lockedUntil) return false;
  if (Date.now() < user.lockedUntil) return true;
  return false;
}

export async function register(username, password, role = 'visitor') {
  const validation = validatePassword(password);
  if (!validation.valid) {
    return { success: false, errors: validation.errors };
  }

  const existing = await DB.getOneByIndex('users', 'username', username);
  if (existing) {
    return { success: false, errors: ['Username already exists'] };
  }

  const { hash, salt } = await Crypto.hashPassword(password);
  const user = {
    username,
    passwordHash: hash,
    passwordSalt: salt,
    role,
    failedAttempts: 0,
    lockedUntil: null,
    banned: false,
    createdAt: Date.now()
  };

  const id = await DB.add('users', user);
  await addAuditLog('user_register', 'system', { userId: id, username, role });
  return { success: true, userId: id };
}

export async function login(username, password) {
  const user = await DB.getOneByIndex('users', 'username', username);
  if (!user) {
    return { success: false, error: 'Invalid credentials' };
  }

  if (user.banned) {
    return { success: false, error: 'Account is banned' };
  }

  if (isAccountLocked(user)) {
    const remaining = Math.ceil((user.lockedUntil - Date.now()) / 60000);
    return { success: false, error: `Account locked. Try again in ${remaining} minute(s).` };
  }

  const valid = await Crypto.verifyPassword(password, user.passwordHash, user.passwordSalt);
  if (!valid) {
    user.failedAttempts = (user.failedAttempts || 0) + 1;
    if (user.failedAttempts >= MAX_ATTEMPTS) {
      user.lockedUntil = Date.now() + LOCKOUT_DURATION;
      user.failedAttempts = 0;
      await DB.put('users', user);
      await addAuditLog('account_locked', username, { reason: 'max_failed_attempts' });
      return { success: false, error: 'Account locked for 15 minutes due to too many failed attempts.' };
    }
    await DB.put('users', user);
    return { success: false, error: 'Invalid credentials', attemptsLeft: MAX_ATTEMPTS - user.failedAttempts };
  }

  // Reset failed attempts
  user.failedAttempts = 0;
  user.lockedUntil = null;
  user.lastLogin = Date.now();
  await DB.put('users', user);

  // Create session
  const token = Crypto.generateId();
  const session = {
    token,
    userId: user.id,
    username: user.username,
    role: user.role,
    createdAt: Date.now(),
    lastActivity: Date.now()
  };

  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
  Store.set('session', session);
  Store.set('currentUser', { id: user.id, username: user.username, role: user.role });

  startIdleTimer();
  await addAuditLog('user_login', username, { userId: user.id });
  return { success: true, session };
}

export function getSession() {
  const raw = localStorage.getItem(SESSION_KEY);
  if (!raw) return null;

  try {
    const session = JSON.parse(raw);
    if (Date.now() - session.lastActivity > SESSION_TIMEOUT) {
      logout();
      return null;
    }
    return session;
  } catch {
    return null;
  }
}

export function refreshSession() {
  const session = getSession();
  if (session) {
    session.lastActivity = Date.now();
    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
    Store.set('session', session);
    startIdleTimer();
    return true;
  }
  return false;
}

export function startIdleTimer() {
  clearTimeout(idleTimer);
  clearTimeout(warningTimer);

  warningTimer = setTimeout(() => {
    Store.set('sessionWarning', true);
  }, SESSION_WARNING);

  idleTimer = setTimeout(() => {
    Store.set('sessionWarning', false);
    Store.set('sessionExpired', true);
    logout();
  }, SESSION_TIMEOUT);
}

export function logout() {
  clearTimeout(idleTimer);
  clearTimeout(warningTimer);
  const session = getSession();
  localStorage.removeItem(SESSION_KEY);
  Store.set('session', null);
  Store.set('currentUser', null);
  if (session) {
    addAuditLog('user_logout', session.username, { userId: session.userId });
  }
}

export function getCurrentUser() {
  const session = getSession();
  if (!session) return null;
  return { id: session.userId, username: session.username, role: session.role };
}

export function hasRole(requiredRoles) {
  const user = getCurrentUser();
  if (!user) return false;
  if (typeof requiredRoles === 'string') requiredRoles = [requiredRoles];
  return requiredRoles.includes(user.role);
}

export function requireAuth() {
  const session = getSession();
  if (!session) {
    window.location.hash = '/login';
    return false;
  }
  refreshSession();
  return true;
}

export function requireRole(roles) {
  if (!requireAuth()) return false;
  if (!hasRole(roles)) {
    window.location.hash = '/';
    return false;
  }
  return true;
}

// Initialize role definitions
export async function initRoles() {
  const existing = await DB.getAll('roles');
  if (existing.length > 0) return;

  const roles = [
    { name: 'visitor', label: 'Regular User', permissions: ['reservations.view', 'reservations.create', 'map.view', 'notifications.view'] },
    { name: 'operator', label: 'Merchant/Operator', permissions: ['reservations.view', 'reservations.create', 'reservations.manage', 'map.view', 'notifications.view', 'devices.unlock', 'devices.view'] },
    { name: 'reviewer', label: 'Reviewer', permissions: ['content.view', 'content.review', 'content.moderate', 'notifications.view', 'map.view'] },
    { name: 'admin', label: 'Administrator', permissions: ['*'] }
  ];

  for (const role of roles) {
    await DB.add('roles', role);
  }
}

export function hasPermission(permission) {
  const user = getCurrentUser();
  if (!user) return false;
  const session = getSession();
  if (!session) return false;
  // Admin has all permissions
  if (user.role === 'admin') return true;
  // Check role-based permissions from store cache
  const roles = Store.get('roles') || [];
  const role = roles.find(r => r.name === user.role);
  if (!role) return false;
  return role.permissions.includes(permission) || role.permissions.includes('*');
}

export async function loadRoles() {
  const roles = await DB.getAll('roles');
  Store.set('roles', roles);
  return roles;
}
"}

