 * Entry Permissions service.
 * - Permission window: 15 min before → 30 min after reservation
 * - Entry policy: single-use (consumed on first unlock) OR multi-use (up to 5 entries)
 */
import DB from '../db.js';
import { addAuditLog } from './audit.js';

const WINDOW_BEFORE_MS = 15 * 60 * 1000; // 15 min before
const WINDOW_AFTER_MS = 30 * 60 * 1000;  // 30 min after

export function calculatePermissionWindow(reservationStartTime) {
  const start = new Date(reservationStartTime).getTime();
  return {
    windowStart: start - WINDOW_BEFORE_MS,
    windowEnd: start + WINDOW_AFTER_MS
  };
}

export function isWithinPermissionWindow(permission, now = Date.now()) {
  return now >= permission.windowStart && now <= permission.windowEnd;
}

export async function createEntryPermission(reservation, policy = 'single-use') {
  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();
  const { windowStart, windowEnd } = calculatePermissionWindow(startTime);

  const permission = {
    reservationId: reservation.id,
    userId: reservation.userId,
    zone: reservation.zone,
    policy,                       // 'single-use' or 'multi-use'
    maxEntries: policy === 'single-use' ? 1 : 5,
    usedEntries: 0,
    windowStart,
    windowEnd,
    status: 'active',            // active, consumed, expired
    createdAt: Date.now()
  };

