  if (!perm) return { success: false, error: 'Permission not found' };

  if (perm.status === 'consumed') {
    return { success: false, error: 'Permission already fully consumed' };
  }

  if (perm.status === 'expired') {
    return { success: false, error: 'Permission has expired' };
  }

  if (!isWithinPermissionWindow(perm)) {
    return { success: false, error: 'Outside permission time window' };
  }

  const before = { ...perm };
  perm.usedEntries += 1;

  if (perm.usedEntries >= perm.maxEntries) {
