{"file_path": "/home/eren/Documents/task4/Harborgate/repo/frontend/js/services/notifications.js", "content": "/**
 * Notification service.
 * - Templates with variables: {reservationId}, {doorName}, etc.
 * - Scheduled reminders: 24h and 1h before reservation start
 * - Local retry: up to 3 attempts
 * - Delivered/failed receipts
 */
import DB from '../db.js';

const MAX_RETRIES = 3;

const TEMPLATES = {
  reservation_approved: 'Your reservation #{reservationId} has been approved.',
  reservation_denied: 'Your reservation #{reservationId} has been denied.',
  reservation_reminder_24h: 'Reminder: Your reservation #{reservationId} at {zone} is in 24 hours.',
  reservation_reminder_1h: 'Reminder: Your reservation #{reservationId} at {zone} is in 1 hour.',
  unlock_success: 'Door "{doorName}" has been unlocked successfully.',
  unlock_failed: 'Failed to unlock door "{doorName}". Please try again.',
  content_flagged: 'Content "{contentTitle}" has been flagged for review.',
  content_published: 'Content "{contentTitle}" has been published.',
  overdue_item: 'Overdue: {itemDescription} requires attention.',
  missing_materials: 'Missing materials for reservation #{reservationId}: {details}.',
  account_locked: 'Your account has been locked due to multiple failed login attempts.',
  user_banned: 'Account "{username}" has been banned. Reason: {reason}'
};

export function resolveTemplate(templateId, variables = {}) {
  let template = TEMPLATES[templateId];
  if (!template) return templateId; // fallback to raw string

  for (const [key, value] of Object.entries(variables)) {
    template = template.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
  }
  return template;
}

export async function createNotification({ userId, templateId, variables, type = 'info', scheduledFor = null }) {
  const message = resolveTemplate(templateId, variables);
  const notification = {
    userId,
    templateId,
    variables,
    message,
    type,
    read: false,
    status: 'pending',          // pending, delivered, failed
    retryCount: 0,
    scheduledFor: scheduledFor || Date.now(),
    createdAt: Date.now(),
    deliveredAt: null,
    failedAt: null
  };

  const id = await DB.add('notifications', notification);
  notification.id = id;

  // Attempt immediate delivery if not scheduled in future
  if (!scheduledFor || scheduledFor <= Date.now()) {
    return deliverNotification(notification);
  }

  return notification;
}

export async function deliverNotification(notification) {
  // In-browser delivery (always succeeds in client-only mode)
  notification.status = 'delivered';
  notification.deliveredAt = Date.now();
  await DB.put('notifications', notification);
  return notification;
}

export async function retryFailedNotifications() {
  const all = await DB.getAll('notifications');
  const failed = all.filter(n => n.status === 'failed' && n.retryCount < MAX_RETRIES);
  const results = [];

  for (const n of failed) {
    n.retryCount += 1;
    try {
      const result = await deliverNotification(n);
      results.push(result);
    } catch {
      if (n.retryCount >= MAX_RETRIES) {
        n.status = 'failed';
        n.failedAt = Date.now();
      }
      await DB.put('notifications', n);
      results.push(n);
    }
  }

  return results;
}

export async function processScheduledNotifications() {
  const all = await DB.getAll('notifications');
  const now = Date.now();
  const due = all.filter(n => n.status === 'pending' && n.scheduledFor && n.scheduledFor <= now);

  for (const n of due) {
    await deliverNotification(n);
  }

  return due.length;
}

export async function scheduleReservationReminders(reservation) {
  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();

  // 24h reminder
  const reminder24h = startTime - 24 * 60 * 60 * 1000;
  if (reminder24h > Date.now()) {
    await createNotification({
      userId: reservation.userId,
      templateId: 'reservation_reminder_24h',
      variables: { reservationId: reservation.id, zone: reservation.zone },
      type: 'info',
      scheduledFor: reminder24h
    });
  }

  // 1h reminder
  const reminder1h = startTime - 60 * 60 * 1000;
  if (reminder1h > Date.now()) {
    await createNotification({
      userId: reservation.userId,
      templateId: 'reservation_reminder_1h',
      variables: { reservationId: reservation.id, zone: reservation.zone },
      type: 'warning',
      scheduledFor: reminder1h
    });
  }
}

export function getTemplates() {
  return { ...TEMPLATES };
}

export async function getUserNotifications(userId) {
  if (userId) {
    return DB.getByIndex('notifications', 'userId', userId);
  }
  return DB.getAll('notifications');
}
"}

