 * Venue Map & POI Management service.
 * - Manually entered coordinates (feet-based display)
 * - Search by radius, administrative zone, polygon geofence
 * - Route planning with estimated walk time
 * - Configurable walk speed (default 3 mph)
 */
import DB from '../db.js';

const DEFAULT_WALK_SPEED_MPH = 3;
const FEET_PER_MILE = 5280;

export function setWalkSpeed(mph) {
  localStorage.setItem('hg_walk_speed', String(mph));
}

export function getWalkSpeed() {
  const stored = localStorage.getItem('hg_walk_speed');
  return stored ? parseFloat(stored) : DEFAULT_WALK_SPEED_MPH;
}

export function distanceFeet(p1, p2) {
  const dx = p1.x - p2.x;
  const dy = p1.y - p2.y;
  return Math.sqrt(dx * dx + dy * dy);
}

export function searchByRadius(pois, center, radiusFeet) {
  return pois.filter(poi => {
    const dist = distanceFeet(center, { x: poi.x, y: poi.y });
    return dist <= radiusFeet;
  });
}

export function searchByZone(pois, zone) {
  return pois.filter(poi => poi.zone === zone);
}

export function pointInPolygon(point, polygon) {
  let inside = false;
  const n = polygon.length;
  for (let i = 0, j = n - 1; i < n; j = i++) {
    const xi = polygon[i].x, yi = polygon[i].y;
    const xj = polygon[j].x, yj = polygon[j].y;
    const intersect = ((yi > point.y) !== (yj > point.y)) &&
      (point.x < (xj - xi) * (point.y - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}

export function searchByPolygon(pois, polygon) {
  return pois.filter(poi => pointInPolygon({ x: poi.x, y: poi.y }, polygon));
}

export function calculateWalkTime(distanceFeetVal, speedMph) {
  const speed = speedMph || getWalkSpeed();
  const distanceMiles = distanceFeetVal / FEET_PER_MILE;
  const hours = distanceMiles / speed;
  const minutes = hours * 60;
  return Math.round(minutes * 10) / 10; // round to 1 decimal
}

export function planRoute(from, to, waypoints = []) {
  const points = [from, ...waypoints, to];
  let totalDistance = 0;

  const segments = [];
  for (let i = 0; i < points.length - 1; i++) {
    const dist = distanceFeet(points[i], points[i + 1]);
    totalDistance += dist;
    segments.push({
      from: points[i],
      to: points[i + 1],
      distanceFeet: Math.round(dist),
      walkTimeMinutes: calculateWalkTime(dist)
    });
  }

  return {
    segments,
    totalDistanceFeet: Math.round(totalDistance),
    totalWalkTimeMinutes: calculateWalkTime(totalDistance),
    suggestedEntryPoint: from
  };
}

export async function addPOI(poi) {
  const record = {
    name: poi.name,
    x: poi.x,
    y: poi.y,
    zone: poi.zone || null,
    type: poi.type || 'general', // entry, exit, amenity, general
    description: poi.description || '',
    createdAt: Date.now()
  };
  const id = await DB.add('pois', record);
  return { ...record, id };
}

export async function updatePOI(poi) {
  await DB.put('pois', poi);
  return poi;
}

export async function deletePOI(id) {
  await DB.remove('pois', id);
}

export async function getAllPOIs() {
  return DB.getAll('pois');
}

export async function saveGeofence(geofence) {
  const record = {
    name: geofence.name,
    zone: geofence.zone || null,
    points: geofence.points, // Array of {x, y}
    createdAt: Date.now()
  };
  const id = await DB.add('geofences', record);
  return { ...record, id };
}

export async function getAllGeofences() {
  return DB.getAll('geofences');
}

export async function deleteGeofence(id) {
  await DB.remove('geofences', id);
}

export function getEntryPoints(pois) {
  return pois.filter(p => p.type === 'entry');
}

export function suggestNearestEntry(pois, target) {
  const entries = getEntryPoints(pois);
  if (entries.length === 0) return null;

  let nearest = entries[0];
  let minDist = distanceFeet(target, { x: entries[0].x, y: entries[0].y });

  for (let i = 1; i < entries.length; i++) {
    const dist = distanceFeet(target, { x: entries[i].x, y: entries[i].y });
    if (dist < minDist) {
      minDist = dist;
      nearest = entries[i];
    }
  }

  return {
    poi: nearest,
    distanceFeet: Math.round(minDist),
    walkTimeMinutes: calculateWalkTime(minDist)
  };
}
"}

