export async function importData(fileContent, password) {
  let bundle;

  const parsed = JSON.parse(fileContent);

  if (parsed.encrypted) {
    if (!password) throw new Error('Password required for encrypted backup');
    bundle = await Crypto.decryptObject(parsed.data, password);
  } else {
    bundle = parsed.data || parsed;
