        <button class="btn btn-danger" id="clear-all-notif">Clear All</button>
      </div>
    </div>
    <div class="filters">
      <select id="notif-status-filter" class="input">
        <option value="">All</option>
        <option value="delivered">Delivered</option>
        <option value="pending">Pending</option>
        <option value="failed">Failed</option>
      </select>
      <select id="notif-type-filter" class="input">
        <option value="">All Types</option>
        <option value="info">Info</option>
        <option value="success">Success</option>
        <option value="warning">Warning</option>
        <option value="error">Error</option>
      </select>
    </div>
    <div id="notifications-table"></div>
    <div class="hint" style="margin-top:16px">
      <strong>Templates available:</strong> ${Object.keys(getTemplates()).join(', ')}
    </div>
  `;

  const columns = [
    { key: 'read', label: '', render: (val) => val ? '' : '<span class="unread-dot"></span>' },
    { key: 'type', label: 'Type', sortable: true, render: (val) => `<span class="badge badge-${val}">${val}</span>` },
    { key: 'message', label: 'Message', sortable: true },
    { key: 'status', label: 'Delivery', sortable: true, render: (val) => {
      const cls = val === 'delivered' ? 'approved' : val === 'failed' ? 'denied' : 'pending';
      return `<span class="badge badge-${cls}">${val}</span>`;
    }},
    { key: 'retryCount', label: 'Retries' },
    { key: 'createdAt', label: 'Created', sortable: true, render: (val) => new Date(val).toLocaleString() },
    { key: 'actions', label: '', render: (_, row) => `
      ${!row.read ? `<button class="btn btn-sm" data-action="read" data-id="${row.id}">Read</button>` : ''}
      <button class="btn btn-sm btn-danger" data-action="delete" data-id="${row.id}">Delete</button>
    `}
  ];

  const tableId = 'notifications';
  Store.initTable(tableId, notifications, { pageSize: 15, sortKey: 'createdAt', sortDir: 'desc' });

  function refresh() {
    renderPaginatedTable(document.getElementById('notifications-table'), tableId, columns, bindActions);
  }
  refresh();

  document.getElementById('notif-status-filter').addEventListener('change', (e) => {
    const s = e.target.value;
    Store.setTableFilter(tableId, s ? (n => n.status === s) : null);
    refresh();
  });

  document.getElementById('notif-type-filter').addEventListener('change', (e) => {
    const t = e.target.value;
    Store.setTableFilter(tableId, t ? (n => n.type === t) : null);
    refresh();
  });

  document.getElementById('retry-failed-btn').addEventListener('click', async () => {
    const results = await retryFailedNotifications();
    showNotification(`Retried ${results.length} notification(s)`, 'info');
    renderNotifications(container);
  });

  document.getElementById('mark-all-read').addEventListener('click', async () => {
    for (const n of notifications) {
      if (!n.read) { n.read = true; await DB.put('notifications', n); }
    }
    showNotification('All marked as read', 'success');
    renderNotifications(container);
  });

  document.getElementById('clear-all-notif').addEventListener('click', async () => {
    await DB.clear('notifications');
    showNotification('Notifications cleared', 'success');
    renderNotifications(container);
  });

  function bindActions() {
    document.querySelectorAll('[data-action="read"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        const n = await DB.get('notifications', Number(btn.dataset.id));
        if (n) { n.read = true; await DB.put('notifications', n); renderNotifications(container); }
      });
    });

    document.querySelectorAll('[data-action="delete"]').forEach(btn => {
      btn.addEventListener('click', async () => {
        await DB.remove('notifications', Number(btn.dataset.id));
        renderNotifications(container);
      });
    });
  }
}
"}

