import assert from 'node:assert/strict';

// === Inline permission logic (mirrors frontend/js/services/permissions.js) ===
const WINDOW_BEFORE_MS = 15 * 60 * 1000;
const WINDOW_AFTER_MS = 30 * 60 * 1000;

function calculatePermissionWindow(reservationStartTime) {
  const start = new Date(reservationStartTime).getTime();
  return {
    windowStart: start - WINDOW_BEFORE_MS,
    windowEnd: start + WINDOW_AFTER_MS
  };
}

function isWithinPermissionWindow(permission, now) {
  return now >= permission.windowStart && now <= permission.windowEnd;
}

function createEntryPermission(startTime, policy = 'single-use') {
  const { windowStart, windowEnd } = calculatePermissionWindow(startTime);
  return {
    policy,
    maxEntries: policy === 'single-use' ? 1 : 5,
    usedEntries: 0,
    windowStart,
    windowEnd,
    status: 'active'
  };
}

function consumeEntry(perm, now) {
  if (perm.status === 'consumed') return { success: false, error: 'Permission already fully consumed' };
  if (perm.status === 'expired') return { success: false, error: 'Permission has expired' };
  if (!isWithinPermissionWindow(perm, now)) return { success: false, error: 'Outside permission time window' };

  perm.usedEntries += 1;
  if (perm.usedEntries >= perm.maxEntries) {
    perm.status = 'consumed';
  }
  return { success: true, permission: perm };
}

describe('Permission Time Window', () => {
  it('should calculate window 15 min before to 30 min after', () => {
    const startTime = '2026-06-15T10:00:00';
    const { windowStart, windowEnd } = calculatePermissionWindow(startTime);
    const start = new Date(startTime).getTime();

    assert.equal(windowStart, start - 15 * 60 * 1000);
    assert.equal(windowEnd, start + 30 * 60 * 1000);
  });

  it('should detect time within window', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime);
    const start = new Date(startTime).getTime();

    assert.equal(isWithinPermissionWindow(perm, start), true);
    assert.equal(isWithinPermissionWindow(perm, start - 10 * 60 * 1000), true); // 10 min before
    assert.equal(isWithinPermissionWindow(perm, start + 20 * 60 * 1000), true); // 20 min after
  });

  it('should detect time outside window (too early)', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime);
    const start = new Date(startTime).getTime();

    assert.equal(isWithinPermissionWindow(perm, start - 20 * 60 * 1000), false); // 20 min before
  });

  it('should detect time outside window (too late)', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime);
    const start = new Date(startTime).getTime();

    assert.equal(isWithinPermissionWindow(perm, start + 31 * 60 * 1000), false); // 31 min after
  });

  it('should allow at exact boundary (15 min before)', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime);
    assert.equal(isWithinPermissionWindow(perm, perm.windowStart), true);
  });

  it('should allow at exact boundary (30 min after)', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime);
    assert.equal(isWithinPermissionWindow(perm, perm.windowEnd), true);
  });
});

describe('Single-Use Permission', () => {
  it('should allow one entry', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'single-use');
    const now = new Date(startTime).getTime();

    assert.equal(perm.maxEntries, 1);
    const result = consumeEntry(perm, now);
    assert.equal(result.success, true);
    assert.equal(perm.status, 'consumed');
  });

  it('should reject second entry on single-use', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'single-use');
    const now = new Date(startTime).getTime();

    consumeEntry(perm, now);
    const result = consumeEntry(perm, now);
    assert.equal(result.success, false);
    assert.ok(result.error.includes('consumed'));
  });
});

describe('Multi-Use Permission', () => {
  it('should allow up to 5 entries', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'multi-use');
    const now = new Date(startTime).getTime();

    assert.equal(perm.maxEntries, 5);

    for (let i = 0; i < 5; i++) {
      const result = consumeEntry(perm, now);
      assert.equal(result.success, true);
    }
    assert.equal(perm.status, 'consumed');
    assert.equal(perm.usedEntries, 5);
  });

  it('should reject 6th entry on multi-use', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'multi-use');
    const now = new Date(startTime).getTime();

    for (let i = 0; i < 5; i++) consumeEntry(perm, now);
    const result = consumeEntry(perm, now);
    assert.equal(result.success, false);
  });

  it('should track used entries count', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'multi-use');
    const now = new Date(startTime).getTime();

    consumeEntry(perm, now);
    assert.equal(perm.usedEntries, 1);
    consumeEntry(perm, now);
    assert.equal(perm.usedEntries, 2);
  });
});

describe('Permission Edge Cases', () => {
  it('should reject entry outside time window', () => {
    const startTime = '2026-06-15T10:00:00';
    const perm = createEntryPermission(startTime, 'single-use');
    const tooEarly = new Date(startTime).getTime() - 20 * 60 * 1000;

    const result = consumeEntry(perm, tooEarly);
    assert.equal(result.success, false);
    assert.ok(result.error.includes('Outside'));
  });

  it('should reject entry on expired permission', () => {
    const perm = {
      policy: 'single-use',
      maxEntries: 1,
      usedEntries: 0,
      windowStart: 0,
      windowEnd: 0,
      status: 'expired'
    };

    const result = consumeEntry(perm, Date.now());
    assert.equal(result.success, false);
    assert.ok(result.error.includes('expired'));
  });
});
"}

