// === Inline device/outbox logic (mirrors frontend/js/services/device.js) ===
const ACK_TIMEOUT = 2000;
const RETRY_INTERVAL = 10000;
const MAX_RETRY_DURATION = 120000;

function createDeviceService() {
  let devices = [];
  let outbox = [];
  let listeners = [];
  let retryTimers = {};
  let nextId = 1;

  function emit(type, payload) {
    for (const l of listeners) l({ type, payload, timestamp: Date.now() });
  }

  return {
    registerDevice(device) {
      const record = { ...device, id: nextId++, status: 'online', lastSeen: Date.now() };
      devices.push(record);
      emit('device:registered', record);
      return record;
    },

    getDevices() { return [...devices]; },

    createCommand(deviceId, reason, actor) {
      if (!reason || reason.length < 10) {
        return { success: false, error: 'Reason must be at least 10 characters' };
      }
      const device = devices.find(d => d.id === deviceId);
      if (!device) return { success: false, error: `Device ${deviceId} not found` };

      const cmd = {
        id: nextId++,
        deviceId,
        type: 'unlock',
        reason,
        actor,
        status: 'pending',
        createdAt: Date.now(),
        ackAt: null,
        retryCount: 0
      };
      outbox.push(cmd);
      return { success: true, command: cmd };
    },

    simulateAck(commandId) {
      const cmd = outbox.find(c => c.id === commandId);
      if (cmd) {
        cmd.status = 'acknowledged';
        cmd.ackAt = Date.now();
        emit('device:ack', { commandId });
      }
    },

    simulateAckTimeout(commandId) {
      const cmd = outbox.find(c => c.id === commandId);
      if (cmd && cmd.status === 'pending') {
        cmd.status = 'queued';
      }
    },

    retryCommand(commandId) {
      const cmd = outbox.find(c => c.id === commandId);
      if (!cmd || cmd.status !== 'queued') return null;

      const elapsed = Date.now() - cmd.createdAt;
      if (elapsed >= MAX_RETRY_DURATION) {
        cmd.status = 'failed';
        return cmd;
      }

      cmd.retryCount += 1;
      cmd.lastRetry = Date.now();

      const device = devices.find(d => d.id === cmd.deviceId);
      if (device && device.status === 'online') {
        cmd.status = 'acknowledged';
        cmd.ackAt = Date.now();
        return cmd;
      }

      return cmd;
    },

    getOutbox() { return [...outbox]; },

    setDeviceStatus(deviceId, status) {
      const device = devices.find(d => d.id === deviceId);
      if (device) device.status = status;
    },

    onEvent(callback) {
      listeners.push(callback);
      return () => { listeners = listeners.filter(l => l !== callback); };
    },

    reset() { devices = []; outbox = []; listeners = []; retryTimers = {}; nextId = 1; }
  };
}

describe('Device Service - Command Creation', () => {
  let svc;

  beforeEach(() => { svc = createDeviceService(); });

  it('should reject reason shorter than 10 characters', () => {
    svc.registerDevice({ name: 'Door 1' });
    const result = svc.createCommand(1, 'short', 'admin');
    assert.equal(result.success, false);
    assert.ok(result.error.includes('10 characters'));
  });

  it('should reject command to unknown device', () => {
    const result = svc.createCommand(999, 'Valid reason text', 'admin');
    assert.equal(result.success, false);
    assert.ok(result.error.includes('not found'));
  });

  it('should create command with valid inputs', () => {
    svc.registerDevice({ name: 'Door 1' });
    const result = svc.createCommand(1, 'Maintenance access needed', 'operator');
    assert.equal(result.success, true);
    assert.equal(result.command.status, 'pending');
    assert.equal(result.command.reason, 'Maintenance access needed');
  });

  it('should store command in outbox', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.createCommand(1, 'Valid reason text here', 'admin');
    assert.equal(svc.getOutbox().length, 1);
  });
});

describe('Device Service - ACK Timeout & Queued State', () => {
  let svc;

  beforeEach(() => { svc = createDeviceService(); });

  it('should transition to queued on ACK timeout', () => {
    svc.registerDevice({ name: 'Door 1' });
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAckTimeout(command.id);
    assert.equal(command.status, 'queued');
  });

  it('should transition to acknowledged on ACK', () => {
    svc.registerDevice({ name: 'Door 1' });
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAck(command.id);
    assert.equal(command.status, 'acknowledged');
    assert.ok(command.ackAt);
  });
});

describe('Device Service - Retry Logic', () => {
  let svc;

  beforeEach(() => { svc = createDeviceService(); });

  it('should retry queued command', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.setDeviceStatus(1, 'offline');
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAckTimeout(command.id);

    const result = svc.retryCommand(command.id);
    assert.equal(result.retryCount, 1);
    assert.equal(result.status, 'queued'); // still offline
  });

  it('should acknowledge on retry when device comes online', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.setDeviceStatus(1, 'offline');
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAckTimeout(command.id);

    svc.setDeviceStatus(1, 'online');
    const result = svc.retryCommand(command.id);
    assert.equal(result.status, 'acknowledged');
  });

  it('should fail after max retry duration (2 minutes)', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.setDeviceStatus(1, 'offline');
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAckTimeout(command.id);

    // Simulate command created 3 minutes ago
    command.createdAt = Date.now() - 180000;
    const result = svc.retryCommand(command.id);
    assert.equal(result.status, 'failed');
  });

  it('should increment retry count', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.setDeviceStatus(1, 'offline');
    const { command } = svc.createCommand(1, 'Valid reason text here', 'admin');
    svc.simulateAckTimeout(command.id);

    svc.retryCommand(command.id);
    svc.retryCommand(command.id);
    assert.equal(command.retryCount, 2);
  });
});

describe('Device Service - Outbox', () => {
  let svc;

  beforeEach(() => { svc = createDeviceService(); });

  it('should track multiple commands', () => {
    svc.registerDevice({ name: 'Door 1' });
    svc.registerDevice({ name: 'Door 2' });
    svc.createCommand(1, 'First door access', 'admin');
    svc.createCommand(2, 'Second door access', 'admin');
    assert.equal(svc.getOutbox().length, 2);
  });

  it('should preserve command history', () => {
    svc.registerDevice({ name: 'Door 1' });
    const { command } = svc.createCommand(1, 'Maintenance access', 'operator');
    svc.simulateAck(command.id);

    const outbox = svc.getOutbox();
    assert.equal(outbox[0].status, 'acknowledged');
    assert.equal(outbox[0].actor, 'operator');
  });
});
"}

