content.text:
1	/**
2	 * Authentication & Session service.
3	 * - Password policy: min 12 chars, 1 upper, 1 lower, 1 number, 1 symbol
4	 * - 5 failed attempts → 15 min lockout
5	 * - 30-min idle timeout, "Extend Session" prompt at 25 min
6	 * - Session token in localStorage
7	 */
8	import DB from '../db.js';
9	import Crypto from '../crypto.js';
10	import Store from '../store.js';
11	import { addAuditLog } from './audit.js';
12	
13	const SESSION_KEY = 'hg_session';
14	const SESSION_TIMEOUT = 30 * 60 * 1000;       // 30 minutes
15	const SESSION_WARNING = 25 * 60 * 1000;       // 25 minutes
16	const LOCKOUT_DURATION = 15 * 60 * 1000;      // 15 minutes
17	const MAX_ATTEMPTS = 5;
18	
19	let idleTimer = null;
20	let warningTimer = null;
21	
22	const PASSWORD_RULES = [
23	  { test: (p) => p.length >= 12, msg: 'Minimum 12 characters' },
24	  { test: (p) => /[A-Z]/.test(p), msg: 'At least 1 uppercase letter' },
25	  { test: (p) => /[a-z]/.test(p), msg: 'At least 1 lowercase letter' },
26	  { test: (p) => /[0-9]/.test(p), msg: 'At least 1 number' },
27	  { test: (p) => /[^A-Za-z0-9]/.test(p), msg: 'At least 1 symbol' }
28	];
29	
30	export function validatePassword(password) {
31	  const failures = PASSWORD_RULES.filter(r => !r.test(password));
32	  return { valid: failures.length === 0, errors: failures.map(f => f.msg) };
33	}
34	
35	export function isAccountLocked(user) {
36	  if (!user.lockedUntil) return false;
37	  if (Date.now() < user.lockedUntil) return true;
38	  return false;
39	}
40	
41	export async function register(username, password, role = 'visitor') {
42	  const validation = validatePassword(password);
43	  if (!validation.valid) {
44	    return { success: false, errors: validation.errors };
45	  }
46	
47	  const existing = await DB.getOneByIndex('users', 'username', username);
48	  if (existing) {
49	    return { success: false, errors: ['Username already exists'] };
50	  }
51	
52	  const { hash, salt } = await Crypto.hashPassword(password);
53	  const user = {
54	    username,
55	    passwordHash: hash,
56	    passwordSalt: salt,
57	    role,
58	    failedAttempts: 0,
59	    lockedUntil: null,
60	    banned: false,
61	    createdAt: Date.now()
62	  };
63	
64	  const id = await DB.add('users', user);
65	  await addAuditLog('user_register', 'system', { userId: id, username, role });
66	  return { success: true, userId: id };
67	}
68	
69	export async function login(username, password) {
70	  const user = await DB.getOneByIndex('users', 'username', username);
71	  if (!user) {
72	    return { success: false, error: 'Invalid credentials' };
73	  }
74	
75	  if (user.banned) {
76	    return { success: false, error: 'Account is banned' };
77	  }
78	
79	  if (isAccountLocked(user)) {
80	    const remaining = Math.ceil((user.lockedUntil - Date.now()) / 60000);
81	    return { success: false, error: `Account locked. Try again in ${remaining} minute(s).` };
82	  }
83	
84	  const valid = await Crypto.verifyPassword(password, user.passwordHash, user.passwordSalt);
85	  if (!valid) {
86	    user.failedAttempts = (user.failedAttempts || 0) + 1;
87	    if (user.failedAttempts >= MAX_ATTEMPTS) {
88	      user.lockedUntil = Date.now() + LOCKOUT_DURATION;
89	      user.failedAttempts = 0;
90	      await DB.put('users', user);
91	      await addAuditLog('account_locked', username, { reason: 'max_failed_attempts' });
92	      return { success: false, error: 'Account locked for 15 minutes due to too many failed attempts.' };
93	    }
94	    await DB.put('users', user);
95	    return { success: false, error: 'Invalid credentials', attemptsLeft: MAX_ATTEMPTS - user.failedAttempts };
96	  }
97	
98	  // Reset failed attempts
99	  user.failedAttempts = 0;
100	  user.lockedUntil = null;
101	  user.lastLogin = Date.now();
102	  await DB.put('users', user);
103	
104	  // Create session
105	  const token = Crypto.generateId();
106	  const session = {
107	    token,
108	    userId: user.id,
109	    username: user.username,
110	    role: user.role,
111	    createdAt: Date.now(),
112	    lastActivity: Date.now()
113	  };
114	
115	  localStorage.setItem(SESSION_KEY, JSON.stringify(session));
116	  Store.set('session', session);
117	  Store.set('currentUser', { id: user.id, username: user.username, role: user.role });
118	
119	  startIdleTimer();
120	  await addAuditLog('user_login', username, { userId: user.id });
121	  return { success: true, session };
122	}
123	
124	export function getSession() {
125	  const raw = localStorage.getItem(SESSION_KEY);
126	  if (!raw) return null;
127	
128	  try {
129	    const session = JSON.parse(raw);
130	    if (Date.now() - session.lastActivity > SESSION_TIMEOUT) {
131	      logout();
132	      return null;
133	    }
134	    return session;
135	  } catch {
136	    return null;
137	  }
138	}
139	
140	export function refreshSession() {
141	  const session = getSession();
142	  if (session) {
143	    session.lastActivity = Date.now();
144	    localStorage.setItem(SESSION_KEY, JSON.stringify(session));
145	    Store.set('session', session);
146	    startIdleTimer();
147	    return true;
148	  }
149	  return false;
150	}
151	
152	export function startIdleTimer() {
153	  clearTimeout(idleTimer);
154	  clearTimeout(warningTimer);
155	
156	  warningTimer = setTimeout(() => {
157	    Store.set('sessionWarning', true);
158	  }, SESSION_WARNING);
159	
160	  idleTimer = setTimeout(() => {
161	    Store.set('sessionWarning', false);
162	    Store.set('sessionExpired', true);
163	    logout();
164	  }, SESSION_TIMEOUT);
165	}
166	
167	export function logout() {
168	  clearTimeout(idleTimer);
169	  clearTimeout(warningTimer);
170	  const session = getSession();
171	  localStorage.removeItem(SESSION_KEY);
172	  Store.set('session', null);
173	  Store.set('currentUser', null);
174	  if (session) {
175	    addAuditLog('user_logout', session.username, { userId: session.userId });
176	  }
177	}
178	
179	export function getCurrentUser() {
180	  const session = getSession();
181	  if (!session) return null;
182	  return { id: session.userId, username: session.username, role: session.role };
183	}
184	
185	export function hasRole(requiredRoles) {
186	  const user = getCurrentUser();
187	  if (!user) return false;
188	  if (typeof requiredRoles === 'string') requiredRoles = [requiredRoles];
189	  return requiredRoles.includes(user.role);
190	}
191	
192	export function requireAuth() {
193	  const session = getSession();
194	  if (!session) {
195	    window.location.hash = '/login';
196	    return false;
197	  }
198	  refreshSession();
199	  return true;
200	}
