217	    { name: 'visitor', label: 'Regular User', permissions: ['reservations.view', 'reservations.create', 'map.view', 'notifications.view'] },
218	    { name: 'operator', label: 'Merchant/Operator', permissions: ['reservations.view', 'reservations.create', 'reservations.manage', 'map.view', 'notifications.view', 'devices.unlock', 'devices.view'] },
219	    { name: 'reviewer', label: 'Reviewer', permissions: ['content.view', 'content.review', 'content.moderate', 'notifications.view', 'map.view'] },
