228	export function hasPermission(permission) {
229	  const user = getCurrentUser();
230	  if (!user) return false;
231	  const session = getSession();
232	  if (!session) return false;
233	  // Admin has all permissions
234	  if (user.role === 'admin') return true;
235	  // Check role-based permissions from store cache
236	  const roles = Store.get('roles') || [];
237	  const role = roles.find(r => r.name === user.role);
238	  if (!role) return false;
239	  return role.permissions.includes(permission) || role.permissions.includes('*');
240	}
