1	/**
2	 * Web Crypto API helpers — AES-GCM encryption with PBKDF2 key derivation.
3	 */
4	const SALT_LENGTH = 16;
5	const IV_LENGTH = 12;
6	const ITERATIONS = 100000;
7	
8	async function deriveKey(password, salt) {
9	  const enc = new TextEncoder();
10	  const keyMaterial = await crypto.subtle.importKey(
11	    'raw',
12	    enc.encode(password),
13	    'PBKDF2',
14	    false,
15	    ['deriveKey']
16	  );
17	
18	  return crypto.subtle.deriveKey(
19	    { name: 'PBKDF2', salt, iterations: ITERATIONS, hash: 'SHA-256' },
20	    keyMaterial,
21	    { name: 'AES-GCM', length: 256 },
22	    false,
23	    ['encrypt', 'decrypt']
24	  );
25	}
26	
27	const Crypto = {
28	  async encrypt(plaintext, password) {
29	    const enc = new TextEncoder();
30	    const salt = crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
31	    const iv = crypto.getRandomValues(new Uint8Array(IV_LENGTH));
32	    const key = await deriveKey(password, salt);
33	
34	    const ciphertext = await crypto.subtle.encrypt(
35	      { name: 'AES-GCM', iv },
36	      key,
37	      enc.encode(plaintext)
38	    );
39	
40	    const combined = new Uint8Array(salt.length + iv.length + ciphertext.byteLength);
41	    combined.set(salt, 0);
42	    combined.set(iv, salt.length);
43	    combined.set(new Uint8Array(ciphertext), salt.length + iv.length);
44	
45	    return btoa(String.fromCharCode(...combined));
46	  },
47	
48	  async decrypt(encoded, password) {
49	    const data = Uint8Array.from(atob(encoded), c => c.charCodeAt(0));
50	    const salt = data.slice(0, SALT_LENGTH);
51	    const iv = data.slice(SALT_LENGTH, SALT_LENGTH + IV_LENGTH);
52	    const ciphertext = data.slice(SALT_LENGTH + IV_LENGTH);
53	
54	    const key = await deriveKey(password, salt);
55	
56	    const plainBuffer = await crypto.subtle.decrypt(
57	      { name: 'AES-GCM', iv },
58	      key,
59	      ciphertext
60	    );
61	
62	    return new TextDecoder().decode(plainBuffer);
63	  },
64	
65	  generateId() {
66	    return crypto.getRandomValues(new Uint8Array(16))
67	      .reduce((s, b) => s + b.toString(16).padStart(2, '0'), '');
68	  },
69	
70	  async hashPassword(password, salt) {
71	    const enc = new TextEncoder();
72	    const saltBytes = salt ? Uint8Array.from(atob(salt), c => c.charCodeAt(0)) : crypto.getRandomValues(new Uint8Array(SALT_LENGTH));
73	    const keyMaterial = await crypto.subtle.importKey(
74	      'raw', enc.encode(password), 'PBKDF2', false, ['deriveBits']
75	    );
76	    const bits = await crypto.subtle.deriveBits(
77	      { name: 'PBKDF2', salt: saltBytes, iterations: ITERATIONS, hash: 'SHA-256' },
78	      keyMaterial,
79	      256
80	    );
81	    const hashB64 = btoa(String.fromCharCode(...new Uint8Array(bits)));
82	    const saltB64 = salt || btoa(String.fromCharCode(...saltBytes));
83	    return { hash: hashB64, salt: saltB64 };
84	  },
85	
86	  async verifyPassword(password, storedHash, storedSalt) {
87	    const { hash } = await this.hashPassword(password, storedSalt);
88	    return hash === storedHash;
89	  },
90	
91	  async encryptObject(obj, password) {
92	    const json = JSON.stringify(obj);
93	    return this.encrypt(json, password);
94	  },
95	
96	  async decryptObject(encrypted, password) {
97	    const json = await this.decrypt(encrypted, password);
98	    return JSON.parse(json);
99	  }
100	};
101	
102	export default Crypto;
103

1	/**
2	 * IndexedDB wrapper for HarborGate data.
3	 */
4	const DB_NAME = 'harborgate';
5	const DB_VERSION = 2;
6	
7	const STORES = {
8	  users: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'username', keyPath: 'username', unique: true }, { name: 'role', keyPath: 'role' }] },
9	  roles: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'name', keyPath: 'name', unique: true }] },
10	  reservations: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'status', keyPath: 'status' }] },
11	  entry_permissions: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'reservationId', keyPath: 'reservationId' }, { name: 'status', keyPath: 'status' }] },
12	  devices: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }, { name: 'status', keyPath: 'status' }] },
13	  pois: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] },
14	  content: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'workflowState', keyPath: 'workflowState' }] },
15	  reports: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'type', keyPath: 'type' }, { name: 'status', keyPath: 'status' }] },
16	  audit_logs: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'actor', keyPath: 'actor' }, { name: 'timestamp', keyPath: 'timestamp' }, { name: 'action', keyPath: 'action' }] },
17	  notifications: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'userId', keyPath: 'userId' }, { name: 'read', keyPath: 'read' }, { name: 'scheduledFor', keyPath: 'scheduledFor' }] },
18	  command_outbox: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'status', keyPath: 'status' }, { name: 'deviceId', keyPath: 'deviceId' }] },
19	  zones: { keyPath: 'id', autoIncrement: true },
20	  geofences: { keyPath: 'id', autoIncrement: true, indexes: [{ name: 'zone', keyPath: 'zone' }] }
21	};
22	
23	let dbInstance = null;
24	
25	function open() {
26	  if (dbInstance) return Promise.resolve(dbInstance);
27	
28	  return new Promise((resolve, reject) => {
29	    const request = indexedDB.open(DB_NAME, DB_VERSION);
30	
31	    request.onupgradeneeded = (event) => {
32	      const db = event.target.result;
33	      for (const [name, opts] of Object.entries(STORES)) {
34	        let store;
35	        if (!db.objectStoreNames.contains(name)) {
36	          store = db.createObjectStore(name, { keyPath: opts.keyPath, autoIncrement: opts.autoIncrement });
37	        } else {
38	          store = event.target.transaction.objectStore(name);
39	        }
40	        if (opts.indexes) {
41	          for (const idx of opts.indexes) {
42	            if (!store.indexNames.contains(idx.name)) {
43	              store.createIndex(idx.name, idx.keyPath, { unique: idx.unique || false });
44	            }
45	          }
46	        }
47	      }
48	    };
49	
50	    request.onsuccess = (event) => {
51	      dbInstance = event.target.result;
52	      resolve(dbInstance);
53	    };
54	
55	    request.onerror = (event) => {
56	      reject(event.target.error);
57	    };
58	  });
59	}
60	
61	async function getStore(storeName, mode = 'readonly') {
62	  const db = await open();
63	  const tx = db.transaction(storeName, mode);
64	  return tx.objectStore(storeName);
65	}
66	
67	function promisify(request) {
68	  return new Promise((resolve, reject) => {
69	    request.onsuccess = () => resolve(request.result);
70	    request.onerror = () => reject(request.error);
71	  });
72	}
73	
74	const DB = {
75	  async getAll(storeName) {
76	    const store = await getStore(storeName);
77	    return promisify(store.getAll());
78	  },
79	
80	  async get(storeName, id) {
81	    const store = await getStore(storeName);
82	    return promisify(store.get(id));
83	  },
84	
85	  async getByIndex(storeName, indexName, value) {
86	    const store = await getStore(storeName);
87	    const index = store.index(indexName);
88	    return promisify(index.getAll(value));
89	  },
90	
91	  async getOneByIndex(storeName, indexName, value) {
92	    const store = await getStore(storeName);
93	    const index = store.index(indexName);
94	    return promisify(index.get(value));
95	  },
96	
97	  async add(storeName, record) {
98	    const store = await getStore(storeName, 'readwrite');
99	    return promisify(store.add(record));
100	  },
101	
102	  async put(storeName, record) {
103	    const store = await getStore(storeName, 'readwrite');
104	    return promisify(store.put(record));
105	  },
106	
107	  async remove(storeName, id) {
108	    const store = await getStore(storeName, 'readwrite');
109	    return promisify(store.delete(id));
110	  },
111	
112	  async clear(storeName) {
113	    const store = await getStore(storeName, 'readwrite');
114	    return promisify(store.clear());
115	  },
116	
117	  async count(storeName) {
118	    const store = await getStore(storeName);
119	    return promisify(store.count());
120	  },
121	
122	  async close() {
123	    if (dbInstance) {
124	      dbInstance.close();
125	      dbInstance = null;
126	    }
127	  }
128	};
129	
130	export default DB;
