1	/**
2	 * Immutable Audit Log service.
3	 * Timestamp format: MM/DD/YYYY 12-hour
4	 * Fields: timestamp, actor, actorRole, action, before, after, details
5	 */
6	import DB from '../db.js';
7	
8	export function formatAuditTimestamp(ts) {
9	  const d = new Date(ts);
10	  const mm = String(d.getMonth() + 1).padStart(2, '0');
11	  const dd = String(d.getDate()).padStart(2, '0');
12	  const yyyy = d.getFullYear();
13	  let h = d.getHours();
14	  const ampm = h >= 12 ? 'PM' : 'AM';
15	  h = h % 12 || 12;
16	  const min = String(d.getMinutes()).padStart(2, '0');
17	  const sec = String(d.getSeconds()).padStart(2, '0');
18	  return `${mm}/${dd}/${yyyy} ${h}:${min}:${sec} ${ampm}`;
19	}
20	
21	export async function addAuditLog(action, actor, details = {}, before = null, after = null) {
22	  const session = JSON.parse(localStorage.getItem('hg_session') || 'null');
23	  const entry = {
24	    timestamp: Date.now(),
25	    formattedTimestamp: formatAuditTimestamp(Date.now()),
26	    actor: actor || session?.username || 'system',
27	    actorRole: session?.role || details.role || 'system',
28	    action,
29	    before: before ? JSON.parse(JSON.stringify(before)) : null,
30	    after: after ? JSON.parse(JSON.stringify(after)) : null,
31	    details: JSON.parse(JSON.stringify(details))
32	  };
33	
34	  // Audit entries are immutable — add only, never update
35	  await DB.add('audit_logs', entry);
36	  return entry;
37	}
38	
39	export async function getAuditLogs(filters = {}) {
40	  let logs = await DB.getAll('audit_logs');
41	
42	  if (filters.actor) {
43	    logs = logs.filter(l => l.actor === filters.actor);
44	  }
45	  if (filters.action) {
46	    logs = logs.filter(l => l.action === filters.action);
47	  }
48	  if (filters.from) {
49	    logs = logs.filter(l => l.timestamp >= filters.from);
50	  }
51	  if (filters.to) {
52	    logs = logs.filter(l => l.timestamp <= filters.to);
53	  }
54	
55	  // Sort newest first
56	  logs.sort((a, b) => b.timestamp - a.timestamp);
57	  return logs;
58	}
