1	/**
2	 * Entry Permissions service.
3	 * - Permission window: 15 min before → 30 min after reservation
4	 * - Entry policy: single-use (consumed on first unlock) OR multi-use (up to 5 entries)
5	 */
6	import DB from '../db.js';
7	import { addAuditLog } from './audit.js';
8	
9	const WINDOW_BEFORE_MS = 15 * 60 * 1000; // 15 min before
10	const WINDOW_AFTER_MS = 30 * 60 * 1000;  // 30 min after
11	
12	export function calculatePermissionWindow(reservationStartTime) {
13	  const start = new Date(reservationStartTime).getTime();
14	  return {
15	    windowStart: start - WINDOW_BEFORE_MS,
16	    windowEnd: start + WINDOW_AFTER_MS
17	  };
18	}
19	
20	export function isWithinPermissionWindow(permission, now = Date.now()) {
21	  return now >= permission.windowStart && now <= permission.windowEnd;
22	}
23	
24	export async function createEntryPermission(reservation, policy = 'single-use') {
25	  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();
26	  const { windowStart, windowEnd } = calculatePermissionWindow(startTime);
27	
28	  const permission = {
29	    reservationId: reservation.id,
30	    userId: reservation.userId,
31	    zone: reservation.zone,
32	    policy,                       // 'single-use' or 'multi-use'
33	    maxEntries: policy === 'single-use' ? 1 : 5,
34	    usedEntries: 0,
35	    windowStart,
36	    windowEnd,
37	    status: 'active',            // active, consumed, expired
38	    createdAt: Date.now()
39	  };
40	
41	  const id = await DB.add('entry_permissions', permission);
42	  await addAuditLog('permission_created', null, {
43	    permissionId: id,
44	    reservationId: reservation.id,
45	    policy,
46	    windowStart: new Date(windowStart).toISOString(),
47	    windowEnd: new Date(windowEnd).toISOString()
48	  });
49	  return { ...permission, id };
50	}
51	
52	export async function consumeEntry(permissionId) {
53	  const perm = await DB.get('entry_permissions', permissionId);
54	  if (!perm) return { success: false, error: 'Permission not found' };
55	
56	  if (perm.status === 'consumed') {
57	    return { success: false, error: 'Permission already fully consumed' };
58	  }
59	
60	  if (perm.status === 'expired') {
61	    return { success: false, error: 'Permission has expired' };
62	  }
63	
64	  if (!isWithinPermissionWindow(perm)) {
65	    return { success: false, error: 'Outside permission time window' };
66	  }
67	
68	  const before = { ...perm };
69	  perm.usedEntries += 1;
70	
71	  if (perm.usedEntries >= perm.maxEntries) {
72	    perm.status = 'consumed';
73	  }
74	
75	  await DB.put('entry_permissions', perm);
76	  await addAuditLog('entry_consumed', null, {
77	    permissionId: perm.id,
78	    usedEntries: perm.usedEntries,
79	    maxEntries: perm.maxEntries
80	  }, before, perm);
81	
82	  return { success: true, permission: perm };
83	}
84	
85	export async function expirePermissions() {
86	  const all = await DB.getAll('entry_permissions');
87	  const now = Date.now();
88	  let expired = 0;
89	
90	  for (const perm of all) {
91	    if (perm.status === 'active' && now > perm.windowEnd) {
92	      perm.status = 'expired';
93	      await DB.put('entry_permissions', perm);
94	      expired++;
95	    }
96	  }
97	
98	  return expired;
99	}
100	
101	export async function getPermissionsForReservation(reservationId) {
102	  return DB.getByIndex('entry_permissions', 'reservationId', reservationId);
103	}
104	
105	export function getPermissionStatusLabel(perm) {
106	  if (perm.status === 'consumed') return 'Consumed';
107	  if (perm.status === 'expired') return 'Expired';
108	  if (isWithinPermissionWindow(perm)) return 'Active';
109	  if (Date.now() < perm.windowStart) return 'Pending';
110	  return 'Expired';
111	}
