1	/**
2	 * Notification service.
3	 * - Templates with variables: {reservationId}, {doorName}, etc.
4	 * - Scheduled reminders: 24h and 1h before reservation start
5	 * - Local retry: up to 3 attempts
6	 * - Delivered/failed receipts
7	 */
8	import DB from '../db.js';
9	
10	const MAX_RETRIES = 3;
11	
12	const TEMPLATES = {
13	  reservation_approved: 'Your reservation #{reservationId} has been approved.',
14	  reservation_denied: 'Your reservation #{reservationId} has been denied.',
15	  reservation_reminder_24h: 'Reminder: Your reservation #{reservationId} at {zone} is in 24 hours.',
16	  reservation_reminder_1h: 'Reminder: Your reservation #{reservationId} at {zone} is in 1 hour.',
17	  unlock_success: 'Door "{doorName}" has been unlocked successfully.',
18	  unlock_failed: 'Failed to unlock door "{doorName}". Please try again.',
19	  content_flagged: 'Content "{contentTitle}" has been flagged for review.',
20	  content_published: 'Content "{contentTitle}" has been published.',
21	  overdue_item: 'Overdue: {itemDescription} requires attention.',
22	  missing_materials: 'Missing materials for reservation #{reservationId}: {details}.',
23	  account_locked: 'Your account has been locked due to multiple failed login attempts.',
24	  user_banned: 'Account "{username}" has been banned. Reason: {reason}'
25	};
26	
27	export function resolveTemplate(templateId, variables = {}) {
28	  let template = TEMPLATES[templateId];
29	  if (!template) return templateId; // fallback to raw string
30	
31	  for (const [key, value] of Object.entries(variables)) {
32	    template = template.replace(new RegExp(`\\{${key}\\}`, 'g'), value);
33	  }
34	  return template;
35	}
36	
37	export async function createNotification({ userId, templateId, variables, type = 'info', scheduledFor = null }) {
38	  const message = resolveTemplate(templateId, variables);
39	  const notification = {
40	    userId,
41	    templateId,
42	    variables,
43	    message,
44	    type,
45	    read: false,
46	    status: 'pending',          // pending, delivered, failed
47	    retryCount: 0,
48	    scheduledFor: scheduledFor || Date.now(),
49	    createdAt: Date.now(),
50	    deliveredAt: null,
51	    failedAt: null
52	  };
53	
54	  const id = await DB.add('notifications', notification);
55	  notification.id = id;
56	
57	  // Attempt immediate delivery if not scheduled in future
58	  if (!scheduledFor || scheduledFor <= Date.now()) {
59	    return deliverNotification(notification);
60	  }
61	
62	  return notification;
63	}
64	
65	export async function deliverNotification(notification) {
66	  // In-browser delivery (always succeeds in client-only mode)
67	  notification.status = 'delivered';
68	  notification.deliveredAt = Date.now();
69	  await DB.put('notifications', notification);
70	  return notification;
71	}
72	
73	export async function retryFailedNotifications() {
74	  const all = await DB.getAll('notifications');
75	  const failed = all.filter(n => n.status === 'failed' && n.retryCount < MAX_RETRIES);
76	  const results = [];
77	
78	  for (const n of failed) {
79	    n.retryCount += 1;
80	    try {
81	      const result = await deliverNotification(n);
82	      results.push(result);
83	    } catch {
84	      if (n.retryCount >= MAX_RETRIES) {
85	        n.status = 'failed';
86	        n.failedAt = Date.now();
87	      }
88	      await DB.put('notifications', n);
89	      results.push(n);
90	    }
91	  }
92	
93	  return results;
94	}
95	
96	export async function processScheduledNotifications() {
97	  const all = await DB.getAll('notifications');
98	  const now = Date.now();
99	  const due = all.filter(n => n.status === 'pending' && n.scheduledFor && n.scheduledFor <= now);
100	
101	  for (const n of due) {
102	    await deliverNotification(n);
103	  }
104	
105	  return due.length;
106	}
107	
108	export async function scheduleReservationReminders(reservation) {
109	  const startTime = new Date(`${reservation.date}T${reservation.time}`).getTime();
110	
111	  // 24h reminder
112	  const reminder24h = startTime - 24 * 60 * 60 * 1000;
113	  if (reminder24h > Date.now()) {
114	    await createNotification({
115	      userId: reservation.userId,
116	      templateId: 'reservation_reminder_24h',
117	      variables: { reservationId: reservation.id, zone: reservation.zone },
118	      type: 'info',
119	      scheduledFor: reminder24h
120	    });
121	  }
122	
123	  // 1h reminder
124	  const reminder1h = startTime - 60 * 60 * 1000;
125	  if (reminder1h > Date.now()) {
126	    await createNotification({
127	      userId: reservation.userId,
128	      templateId: 'reservation_reminder_1h',
129	      variables: { reservationId: reservation.id, zone: reservation.zone },
130	      type: 'warning',
131	      scheduledFor: reminder1h
132	    });
133	  }
134	}
135	
136	export function getTemplates() {
137	  return { ...TEMPLATES };
138	}
139	
140	export async function getUserNotifications(userId) {
141	  if (userId) {
142	    return DB.getByIndex('notifications', 'userId', userId);
143	  }
144	  return DB.getAll('notifications');
145	}
