1	/**
2	 * Venue Map & POI Management service.
3	 * - Manually entered coordinates (feet-based display)
4	 * - Search by radius, administrative zone, polygon geofence
5	 * - Route planning with estimated walk time
6	 * - Configurable walk speed (default 3 mph)
7	 */
8	import DB from '../db.js';
9	
10	const DEFAULT_WALK_SPEED_MPH = 3;
11	const FEET_PER_MILE = 5280;
12	
13	export function setWalkSpeed(mph) {
14	  localStorage.setItem('hg_walk_speed', String(mph));
15	}
16	
17	export function getWalkSpeed() {
18	  const stored = localStorage.getItem('hg_walk_speed');
19	  return stored ? parseFloat(stored) : DEFAULT_WALK_SPEED_MPH;
20	}
21	
22	export function distanceFeet(p1, p2) {
23	  const dx = p1.x - p2.x;
24	  const dy = p1.y - p2.y;
25	  return Math.sqrt(dx * dx + dy * dy);
26	}
27	
28	export function searchByRadius(pois, center, radiusFeet) {
29	  return pois.filter(poi => {
30	    const dist = distanceFeet(center, { x: poi.x, y: poi.y });
31	    return dist <= radiusFeet;
32	  });
33	}
34	
35	export function searchByZone(pois, zone) {
36	  return pois.filter(poi => poi.zone === zone);
37	}
38	
39	export function pointInPolygon(point, polygon) {
40	  let inside = false;
41	  const n = polygon.length;
42	  for (let i = 0, j = n - 1; i < n; j = i++) {
43	    const xi = polygon[i].x, yi = polygon[i].y;
44	    const xj = polygon[j].x, yj = polygon[j].y;
45	    const intersect = ((yi > point.y) !== (yj > point.y)) &&
46	      (point.x < (xj - xi) * (point.y - yi) / (yj - yi) + xi);
47	    if (intersect) inside = !inside;
48	  }
49	  return inside;
50	}
51	
52	export function searchByPolygon(pois, polygon) {
53	  return pois.filter(poi => pointInPolygon({ x: poi.x, y: poi.y }, polygon));
54	}
55	
56	export function calculateWalkTime(distanceFeetVal, speedMph) {
57	  const speed = speedMph || getWalkSpeed();
58	  const distanceMiles = distanceFeetVal / FEET_PER_MILE;
59	  const hours = distanceMiles / speed;
60	  const minutes = hours * 60;
61	  return Math.round(minutes * 10) / 10; // round to 1 decimal
62	}
63	
64	export function planRoute(from, to, waypoints = []) {
65	  const points = [from, ...waypoints, to];
66	  let totalDistance = 0;
67	
68	  const segments = [];
