    timestamp: Date.now(),
    formattedTimestamp: formatAuditTimestamp(Date.now()),
    actor: actor || 'system',
    actorRole,
    action,
    before: before ? JSON.parse(JSON.stringify(before)) : null,
    after: after ? JSON.parse(JSON.stringify(after)) : null,
